1207	\begin{lemma}[Pullback along an isomorphism is an equivalence of module categories]
1208	  \label{lem:pullbackIsoEquivalenceOfIso}
1209	  \lean{AlgebraicGeometry.pullbackIsoEquivalenceOfIso}
1210	  \uses{def:pushforward_base_change_map}
1211	  Let \(f : X \to Y\) be an isomorphism of schemes. Then the pullback functor on
1212	  \(\mathcal{O}\)-modules \(f^* : Y\text{-}\mathbf{Mod} \to X\text{-}\mathbf{Mod}\) is
1213	  one half of an equivalence of categories
1214	  \(Y\text{-}\mathbf{Mod} \simeq X\text{-}\mathbf{Mod}\), with quasi-inverse
1215	  \((f^{-1})^*\).
1216	\end{lemma}
1217	\begin{proof}
1218	  Assemble the equivalence from the functor \(f^*\) and the candidate inverse
1219	  \((f^{-1})^*\). The unit and counit isomorphisms are built from the pseudofunctor
1220	  coherences of pullback: \((f^{-1})^* \circ f^* \cong (f \circ f^{-1})^* = \mathrm{id}^*
1221	  \cong \mathrm{id}\) and symmetrically, using
1222	  \(f \circ f^{-1} = \mathrm{id}_Y\), \(f^{-1} \circ f = \mathrm{id}_X\)
1223	  (composition-of-pullbacks, congruence under equal maps, and pullback-of-identity).
1224	  The triangle identities are forced by these coherences.
1225	\end{proof}
1226	
1227	\begin{lemma}[The pullback functor along an isomorphism is an equivalence]
1228	  \label{lem:pullback_isEquivalence_of_iso}
1229	  \lean{AlgebraicGeometry.pullback_isEquivalence_of_iso}
1230	  \uses{lem:pullbackIsoEquivalenceOfIso}
1231	  Consequently, for an isomorphism \(f : X \to Y\) the functor
1232	  \(f^* : Y\text{-}\mathbf{Mod} \to X\text{-}\mathbf{Mod}\) is an equivalence of
1233	  categories. In particular its adjunction unit is a natural isomorphism, so
1234	  \((\eta_{f})_{W}\) is invertible on every object \(W\).
1235	\end{lemma}
1236	\begin{proof}
1237	  The functor underlying the equivalence of
1238	  \cref{lem:pullbackIsoEquivalenceOfIso} is exactly \(f^*\), so \(f^*\) is an
1239	  equivalence; an equivalence's unit is a natural isomorphism.
1240	\end{proof}
